// NocoDB 설정 데이터
const nocoResp = $('NocoDB 프롬프트 조회').first().json;
const promptData = (nocoResp.list && nocoResp.list.length > 0) ? nocoResp.list[0] : {};

// NocoDB FAQ 데이터 (오류 또는 비어있으면 인라인 폴백 사용)
const faqNodeResult = $input.first().json;
const faqList = (!faqNodeResult.error && faqNodeResult.list && faqNodeResult.list.length > 0)
  ? faqNodeResult.list : [];

// 웹훅 원본 데이터
const webhookJson = $('Webhook POST').first().json;
const body = webhookJson.body || webhookJson;
const sessionId = (body.sessionId || '').trim();
const message = (body.message || '').trim();
const userName = (body.userName || '').trim();
const isLoggedIn = body.isLoggedIn === true || body.isLoggedIn === 'true';

if (!message) throw new Error('메시지가 비어 있습니다.');

// 시스템 프롬프트 (FAQ는 분리 처리하여 LLM 호출 시에만 포함)
const systemPrompt = (promptData.system_prompt || '당신은 프레스코21 쇼핑몰 AI 상담사입니다.')
  + '\n\n## 에스컬레이션 기준\n' + (promptData.escalation_rules || '');

// ========== 의도 분류 ==========

// 1. 인사 감지 (20자 미만 + 인사 키워드)
const greetingKws = ['안녕', '하이', 'hi', 'hello', '헬로', '처음 왔어', '처음이에'];
const isGreeting = message.length < 20 && greetingKws.some(kw => message.toLowerCase().includes(kw));

// 2. 에스컬레이션 선행 감지 (LLM 없이 즉시 판단)
// '환불' 자체는 제거 → '부분 환불', '환불 방법' 등 정보성 질문은 FAQ로 분기
const escKws = [
  '환불해', '환불 요청', '환불 처리', '환불해주세요',
  '불량', '파손', '오배송', '클레임', '상담원', '담당자',
  '사람과 통화', '전화 연결', '직접 상담', '가격 협의', '납기', '결제 오류'
];
const hasEscalation = escKws.some(kw => message.includes(kw));
const hasOrderNum = /주문.{0,5}\d{5,}/.test(message);

// 3. FAQ 키워드 매칭 (인라인 폴백 30개)
const inlineFAQ = [
  // 배송
  { id: 'D01', keywords: ['배송','택배','출고','도착','배달','며칠','소요'],
    answer: '평일 오후 2시 이전 결제 시 당일 출고, 택배 1~2일 소요됩니다 🌿' },
  { id: 'D02', keywords: ['제주','도서산간','추가 배송비'],
    answer: '제주/도서산간 지역은 추가 배송비가 발생할 수 있어요. 주문 시 자동 계산됩니다 ✨' },
  { id: 'D03', keywords: ['무료배송','배송비 기준','얼마부터'],
    answer: '5만원 이상 구매 시 무료배송이에요 🌸' },
  // 교환/반품
  { id: 'R01', keywords: ['교환','반품','반환','바꾸고','돌려','교환 방법'],
    answer: '수령 후 7일 이내 미개봉 상태면 가능해요. 왕복 택배비는 고객님 부담, 불량은 무료입니다 ✨' },
  { id: 'R02', keywords: ['주문 제작','커스텀','맞춤 제작'],
    answer: '주문 제작 상품은 교환/반품이 불가해요 🌿' },
  // 강사회원
  { id: 'I01', keywords: ['강사','도매','등업','강사 신청','강사회원'],
    answer: '사업자등록증(원예) 또는 원예 자격증 준비 후 신청해 주세요 🌸 승인 1~2영업일. https://nocodb.pressco21.com/apply' },
  { id: 'I02', keywords: ['강사 승인','승인 언제','처리 중','신청 확인'],
    answer: '승인은 1~2영업일 내 처리돼요 ✨ 평일 기준, 주말/공휴일 제외입니다.' },
  { id: 'I03', keywords: ['강사 혜택','도매가','할인 혜택'],
    answer: '강사회원은 전 상품 도매가 구매 및 전용 할인이 적용돼요 🌿' },
  // 결제
  { id: 'P01', keywords: ['결제','카드','무통장','페이','결제 방법'],
    answer: '신용카드, 무통장입금, 카카오페이, 네이버페이로 결제 가능해요 ✨' },
  { id: 'P02', keywords: ['무통장 기한','입금 기한','72시간','자동 취소'],
    answer: '무통장입금은 주문 후 72시간 이내 입금해 주세요. 미입금 시 자동 취소됩니다 🌿' },
  { id: 'P03', keywords: ['주문 수정','주문 취소','취소 방법','수정 가능','취소 가능'],
    answer: '주문 수정/취소는 출고 전에만 가능해요 🌿 평일 10~18시에 채널톡이나 전화로 빠르게 연락해 주세요!' },
  { id: 'P04', keywords: ['세금계산서','사업자','계산서 발급','현금영수증'],
    answer: '사업자 구매 후 이메일로 사업자번호와 수신 이메일을 보내주시면 세금계산서 발급해드려요 ✨' },
  { id: 'P05', keywords: ['해외 배송','해외','국제 배송','외국'],
    answer: '현재는 국내 배송만 운영 중이에요 🌿 해외 배송은 추후 안내드릴게요.' },
  { id: 'P06', keywords: ['부분 환불','일부 환불','환불 방법','환불 가능','환불 조건'],
    answer: '부분 환불은 상담 후 개별적으로 처리돼요 🌸 채널톡이나 전화로 문의해 주시면 안내드릴게요.' },
  // 영업시간
  { id: 'H01', keywords: ['영업시간','몇 시','운영 시간','전화 가능'],
    answer: '평일 10시~18시 운영, 점심 12~13시예요. 토/일/공휴일은 휴무입니다 🌸' },
  // 상품
  { id: 'S01', keywords: ['압화','누름꽃','눌러서 말린'],
    answer: '압화는 꽃을 눌러 말린 재료로 레진공예·캔들·액자 등에 활용돼요 🌸' },
  { id: 'S02', keywords: ['레진','키트','초보자','세트','입문'],
    answer: '초보자용 레진공예 키트가 준비되어 있어요 🌿 자사몰에서 "레진 키트"로 검색해 보세요!' },
  { id: 'S03', keywords: ['압화 보관','보관 방법','직사광선','방습','보관법'],
    answer: '압화는 직사광선을 피해 서늘하고 건조한 곳에 보관해 주세요 🌿 방습제와 함께 밀폐 용기에 넣으면 오래 보존돼요!' },
  { id: 'S04', keywords: ['드라이플라워','압화 차이','차이점','드라이 vs 압화'],
    answer: '드라이플라워는 입체적으로 건조한 꽃, 압화는 납작하게 눌러 말린 꽃이에요 🌸 레진·액자엔 압화, 꽃다발·인테리어엔 드라이플라워가 잘 어울려요.' },
  { id: 'S05', keywords: ['하바리움','오일','미네랄오일','실리콘오일','하바리움 오일'],
    answer: '하바리움용 오일은 미네랄오일(투명도 높음)과 실리콘오일(변색 적음) 두 종류예요 ✨ 용도에 맞게 선택해 보세요!' },
  { id: 'S06', keywords: ['대량','단체','대량 주문','단체 구매','대량 할인'],
    answer: '강사회원은 도매가로 대량 구매가 가능해요 🌿 별도 납품 문의는 채널톡이나 전화(평일 10~18시)로 연락해 주세요.' },
  { id: 'S07', keywords: ['사이즈','규격','크기','치수','용량','스펙'],
    answer: '상품별 사이즈와 규격은 각 상품 페이지 상세 설명에서 확인하실 수 있어요 ✨' },
  { id: 'S08', keywords: ['재고','품절','재입고','입고','언제 들어'],
    answer: '실시간 재고는 자사몰 상품 페이지에서 확인 가능해요 🌿 품절 시 "재입고 알림" 신청을 해두시면 알려드려요!' },
  { id: 'S09', keywords: ['레진 키트','키트 구성','레진 세트 구성','키트 내용물'],
    answer: '레진공예 키트는 투명레진+경화제+몰드+압화+기본 도구 세트로 구성되어 있어요 🌸 바로 시작할 수 있어요!' },
  // 기타
  { id: 'E01', keywords: ['클래스','수업','강의','온라인 클래스','배울 수 있어'],
    answer: '온라인 클래스와 협력 강사 클래스를 운영 중이에요 🌸 자세한 일정은 자사몰 공지사항이나 인스타그램에서 확인해 보세요!' },
  { id: 'E02', keywords: ['납품','위탁','B2B','도매 납품','위탁 판매'],
    answer: '납품/위탁 판매 문의는 채널톡이나 전화(평일 10~18시)로 연락해 주시면 담당자가 안내해 드려요 🌿' },
  { id: 'E03', keywords: ['선물 포장','포장','선물 박스','선물용'],
    answer: '유료 선물 포장 서비스가 있어요 ✨ 주문 시 옵션에서 선물 포장을 선택해 주세요!' },
  { id: 'E04', keywords: ['카카오','카카오채널','채팅 상담','실시간 문의'],
    answer: '채널톡 실시간 상담(우측 하단 버튼)으로 연결하시거나 카카오 채널로도 문의 가능해요 🌸 평일 10~18시 운영합니다.' },
  { id: 'E05', keywords: ['인스타','인스타그램','SNS','팔로우','소셜미디어'],
    answer: '인스타그램 @foreverlove_co_kr 을 팔로우해 주세요 🌸 최신 상품과 공예 팁을 가장 먼저 받아보실 수 있어요!' },
  { id: 'E06', keywords: ['클래스 예약','강사 클래스','수강 신청','파트너클래스','꽃공예 클래스'],
    answer: '협력 강사의 꽃공예 클래스는 파트너클래스 플랫폼에서 예약 가능해요 🌸 다양한 클래스가 준비되어 있어요!' }
];

const sourceList = faqList.length > 0 ? faqList : inlineFAQ;
let faqMatch = null, faqScore = 0;

for (const faq of sourceList) {
  if (faq.active === false) continue;
  // NocoDB FAQ 테이블: keywords 필드는 쉼표 구분 문자열
  // 인라인 폴백: keywords 필드는 배열
  const keywords = faqList.length > 0
    ? (faq.keywords || '').split(',').map(k => k.trim()).filter(Boolean)
    : (faq.keywords || []);
  let score = 0;
  for (const kw of keywords) {
    if (kw && message.includes(kw)) score++;
  }
  // 짧은 메시지(15자 미만)는 1개 매칭으로 충분
  const threshold = message.length < 15 ? 1 : 2;
  if (score >= threshold && score > faqScore) {
    faqScore = score;
    faqMatch = faq;
  }
}

// ========== 최종 의도 결정 ==========
let intent, faqAnswer = null, faqId = null;

if (isGreeting) {
  intent = 'greeting';
} else if (hasEscalation || hasOrderNum) {
  intent = 'escalation';
} else if (faqMatch) {
  intent = 'faq_matched';
  faqAnswer = faqMatch.answer || faqMatch.Answer;
  faqId = String(faqMatch.id || faqMatch.Id || '');
} else {
  intent = 'general';
}

return [{ json: { sessionId, message, userName, isLoggedIn, intent, faqAnswer, faqId, systemPrompt } }];

