// AI 응답에서 [ESCALATE] 태그 감지
const aiOutput = $input.first().json.output || '';
const codeData = $('Code: FAQ 매칭+의도 분류').first().json;
const customerMessage = codeData.message || '';

// 에스컬레이션 감지 (3-layer)
const hasEscalateTag = aiOutput.includes('[ESCALATE]');
const hasOrderNumber = /주문.{0,5}\d{5,}/.test(customerMessage);
const escalationKeywords = [
  '환불해', '환불 요청', '환불 처리', '환불해주세요',
  '불량', '파손', '오배송', '클레임', '견적', '할인 요청',
  '사람과 통화', '상담원', '담당자 연결', '전화 연결', '직접 상담',
  '가격 협의', '납기', '대량 주문', '결제 오류'
];
const hasKeyword = escalationKeywords.some(function(kw) { return customerMessage.includes(kw); });
const escalated = hasEscalateTag || hasOrderNumber || hasKeyword;

// 응답 정리 (마크다운 제거)
var reply = aiOutput
  .replace(/\[ESCALATE\]/g, '')
  .replace(/\*\*/g, '')
  .replace(/\*/g, '')
  .replace(/^#{1,6}\s/gm, '')
  .replace(/^[-*]\s/gm, '')
  .replace(/^\d+\.\s/gm, '')
  .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// 길이 제한 300자 (Tool 결과 포함 대비 넉넉하게)
if (reply.length > 300) {
  var cutPoint = reply.lastIndexOf('.', 300);
  if (cutPoint < 100) cutPoint = reply.lastIndexOf(' ', 300);
  if (cutPoint < 100) cutPoint = 300;
  reply = reply.substring(0, cutPoint + 1).trim();
}

return [{
  json: {
    reply: reply,
    escalated: escalated,
    sessionId: codeData.sessionId,
    customerMessage: customerMessage,
    userName: codeData.userName,
    isLoggedIn: codeData.isLoggedIn,
    rawAiOutput: aiOutput
  }
}];

